import React, { useEffect, useState } from 'react';
import './css/manageOfficers.css';
import 'bootstrap/dist/css/bootstrap.min.css'; // Import Bootstrap CSS

const ManageOfficers = () => {
  const [officers, setOfficers] = useState([]);

  useEffect(() => {
    const fetchOfficers = async () => {
      try {
        const response = await fetch('http://localhost:8088/api/admin/get-all-users');
        if (!response.ok) {
          throw new Error('Failed to fetch officers');
        }
        const data = await response.json();
        setOfficers(data); // Assuming data is an array of officer objects
      } catch (error) {
        console.error(error);
        // Handle error (e.g., set an error state)
      }
    };

    fetchOfficers();
  }, []);

  return (
    <div className="manage-officers">
      <h2>Manage Officers</h2>
      <table className="table table-striped">
        <thead>
          <tr>
            <th>ID</th>
            <th>Name</th>
            <th>Role</th>
            <th>Email</th>
            <th>Action</th>
          </tr>
        </thead>
        <tbody>
          {officers.length === 0 ? (
            <tr>
              <td colSpan="5" className="text-center">No officers found.</td>
            </tr>
          ) : (
            officers.map((officer, index) => (
              <tr key={officer.id || index}>
                <td>{officer.id}</td>
                <td>{officer.name}</td>
                <td>{officer.role}</td>
                <td>{officer.email}</td>
                <td>
                  <button className="btn btn-primary btn-sm">Edit</button>
                  <button className="btn btn-danger btn-sm ms-2">Delete</button>
                </td>
              </tr>
            ))
          )}
        </tbody>
      </table>
    </div>
  );
};

export default ManageOfficers;
